  ('lei_sancionada', 'estadual', 'GO', 'lei', '20.656', 2019, '2019-12-18', 'Institui medidas facilitadoras para que o contribuinte negocie seus débitos relacionados às multas pecuniárias aplicadas pela Superintendência de Proteção aos Direitos do Consumidor - PROCON Goiás, da Secretaria de Estado da Segurança Pública, aos infratores das normas de proteção e defesa do consumidor, durante a Semana de Conciliação de 2019 ou em data posteriormente definida, nas condições e situações que menciona, e dá outras providências.', 'RONALDO CAIADO', 'titular', 'https://legisla.casacivil.go.gov.br/pesquisa_legislacao/100857', 'Casa Civil do Estado de Goias - Legisla Goias', NULL, 'GO-LEGISLA:100857', '{"source": "Legisla Goias Casa Civil", "data_real": true, "fluxo": "5B", "case_id": "ronaldo-caiado-go-lote-b-lei-20656", "curation_batch_id": "ronaldo-caiado-go-lote-b-20260502", "coverage_scope": "completo_go_lote_b_20260502", "coverage_id": "ronaldo-caiado-go-completo-leis-2019-01-01-2026-03-27", "legisla_go_id": 100857, "tipo_legislacao_api": 2, "projetos_lei_mixed": false, "historico_politico_id_inferido_por_data": true, "signatario_verificado_por": "conteudo_sem_formatacao_full_text"}'),
