  ('lei_sancionada', 'estadual', 'GO', 'lei', '22.447', 2023, '2023-12-07', 'Altera as Leis nº 21.792, de 16 de fevereiro de 2023, que estabelece a organização administrativa básica do Poder Executivo e dá outras providências; nº 20.756, de 28 de janeiro de 2020, que dispõe sobre o regime jurídico dos servidores públicos civis do Estado de Goiás, das autarquias e fundações públicas estaduais, e dá outras providências; e nº 19.020, de 30 de setembro de 2015, que ratifica o Protocolo de Intenções firmado entre os Estados de Goiás, Mato Grosso, Mato Grosso do Sul, Rondônia ', 'RONALDO CAIADO', 'titular', 'https://legisla.casacivil.go.gov.br/pesquisa_legislacao/108202', 'Casa Civil do Estado de Goias - Legisla Goias', NULL, 'GO-LEGISLA:108202', '{"source": "Legisla Goias Casa Civil", "data_real": true, "fluxo": "5B", "case_id": "ronaldo-caiado-go-lote-b-lei-22447", "curation_batch_id": "ronaldo-caiado-go-lote-b-20260502", "coverage_scope": "completo_go_lote_b_20260502", "coverage_id": "ronaldo-caiado-go-completo-leis-2019-01-01-2026-03-27", "legisla_go_id": 108202, "tipo_legislacao_api": 2, "projetos_lei_mixed": false, "historico_politico_id_inferido_por_data": true, "signatario_verificado_por": "conteudo_sem_formatacao_full_text"}'),
