  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  c.id AS candidato_id,
  (
    SELECT hp.id
    FROM historico_politico hp
    WHERE hp.candidato_id = c.id
      AND hp.tipo_evento = 'mandato'
      AND hp.estado = 'GO'
      AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
      AND hp.periodo_inicio <= seed.ano
      AND (hp.periodo_fim IS NULL OR hp.periodo_fim >= seed.ano)
    ORDER BY hp.periodo_inicio DESC
    LIMIT 1
  ) AS historico_politico_id,
  seed.tipo_relacao,
  seed.esfera,
  seed.uf_norma,
  seed.tipo_norma,
  seed.numero,
  seed.ano,
  seed.data_norma::date,
  seed.ementa,
  seed.signatario,
  seed.autoridade_papel,
  seed.fonte_primaria_url,
  seed.fonte_primaria_titulo,
  seed.fonte_tramitacao_url,
  seed.identificador_fonte,
  seed.metadata::jsonb
FROM candidatos c
CROSS JOIN _seed_ronaldo_caiado_go_lote_b seed
WHERE c.slug = 'ronaldo-caiado'
  AND NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = c.id
      AND lme.identificador_fonte = seed.identificador_fonte
  );
